      'Content-Type': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      'Content-Disposition': `attachment; filename="${safeName}_Offer_Template.xlsx"`,
    });
    res.send(data.buffer);
  });
};

exports.importFactoryRFQ = (req, res) => {
