const RoleService = require("../services/role.service")
const { getUserInfo } = require("../helpers/auth")

const getRoles = async (req, res) => {
    const roles = await RoleService.getRoles();
    res.json(roles);
}

const getRolePermissions = async (req, res) => {
    const rolePermissions = await RoleService.getRolePermissions();
    res.json(rolePermissions);
}

const getUIElements = async (req, res) => {
    const uiElements = await RoleService.getUIElements();
    res.json(uiElements);
}

const PRIVILEGED_PERMISSION_ROLES = ['admin', 'production', 'sourcing_manager'];

const getUserRolePermissions = async (req, res) => {
    const userId = req.params.userId;
    const caller = await getUserInfo(req.headers.authorization);
    if (!caller) {
        return res.status(403).send("Invalid Token");
    }

    const isOwnUser = String(caller.user_id) === String(userId);
    const canReadAnyUser = PRIVILEGED_PERMISSION_ROLES.includes(caller.role);
    if (!isOwnUser && !canReadAnyUser) {
        return res.status(403).send("You are not authorized to access this resource");
    }

    const userRolePermissions = await RoleService.getUserRolePermissions(userId);
    res.json(userRolePermissions);
}

module.exports = {
    getRoles,
    getRolePermissions,
    getUIElements,
    getUserRolePermissions
}

